eState createState() => _GuessGameState(); } class _GuessGameState extends State<GuessGame> { int target = Random().nextInt(100); String msg = "1-100 arasi sayi tuttum"; void check(String v) { int? n = int.tryParse(v); if (n == null) return; setState(() { if (n < target) msg = "Daha BUYUK"; else if (n > target) msg = "Daha KUCUK"; else msg = "BULDUN!"; }); } @override Widget build(BuildContext context) { return Scaffold(appBar: AppBar(title: Text("Oyun")), body: Column(children: [Text(msg), TextField(onSubmitted: check, keyboardType: TextInputType.number)])); } }
